  1→import { distance } from '@/geometry/point';
  2→import { distanceToSegment } from '@/geometry/line';
  3→import { doorOutlineOnWall, windowOutlineOnWall, wallLength, wallOutline, projectPointOnWall } from '@/geometry/wallGeometry';
  4→import { pointInPolygon } from '@/geometry/polygon';
  5→
  6→function hitTest(modelPos, floor, hitRadius) {
  7→  // Hit test doors first (smaller targets, higher priority)
  8→  for (const door of floor.doors) {
  9→    const wall = floor.walls.find(w => w.id === door.wallId);
 10→    if (!wall) continue;
 11→    const info = doorOutlineOnWall(wall, door);
 12→    const poly = [info.p1, info.p2, info.p3, info.p4];
 13→    if (pointInPolygon(modelPos, poly)) {
 14→      return { id: door.id, type: 'door' };
 15→    }
 16→  }
 17→
 18→  // Hit test windows
 19→  for (const win of floor.windows) {
 20→    const wall = floor.walls.find(w => w.id === win.wallId);
 21→    if (!wall) continue;
 22→    const info = windowOutlineOnWall(wall, win);
 23→    const poly = [info.p1, info.p2, info.p3, info.p4];
 24→    if (pointInPolygon(modelPos, poly)) {
 25→      return { id: win.id, type: 'window' };
 26→    }
 27→  }
 28→
 29→  // Hit test walls
 30→  for (const wall of floor.walls) {
 31→    const outline = wallOutline(wall);
 32→    if (pointInPolygon(modelPos, outline)) {
 33→      return { id: wall.id, type: 'wall' };
 34→    }
 35→  }
 36→
 37→  return null;
 38→}
