}
```

And in the main `PropertiesPanel` component, add the room case in the `if/else` chain:

```js
} else if (selectedType === 'room') {
  const room = floor.rooms.find(r => r.id === selectedId);
  if (room) {
    content = <RoomProperties room={room} dispatch={dispatch} floorId={activeFloorId} />;
  }
}
```

Also update `handleDelete` to handle rooms:

```js
} else if (selectedType === 'room') {
  dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
}
```

**D. Sidebar in `Sidebar.jsx`**

Add a Rooms section (following the Walls/Doors/Windows pattern):

```jsx
<div className={styles.section}>
  <div className={styles.sectionTitle}>
    Rooms <span className={styles.count}>{floor.rooms.length}</span>
  </div>
  {floor.rooms.map(r => (
    <div
      key={r.id}
