      fill="none"
      stroke="var(--color-selection)"
      strokeWidth={2}
      strokeDasharray="6 3"
      vectorEffect="non-scaling-stroke"
    />
  );
}
```

---

## Change 8: Pass `selectedId` to RoomRenderer in `SvgCanvas.jsx`

Change line 198:
```jsx
<RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
```

---

## Change 9: Room hit testing in `selectHandler.js`

Add room hit test **after** walls (lower priority) in the `hitTest` function, before `return null`:

```js
for (const room of floor.rooms) {
  if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
    return { id: room.id, type: 'room' };
  }
}
```

`pointInPolygon` is already imported. Also add room delete in `onKeyDown`:

```js
} else if (selectedType === 'room') {
  dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
}
```

---

## Change 10: "Detect Rooms" button in `Toolbar.jsx`

Add to the third button group (alongside Grid/Snap). The toolbar already has `useProject` (for `isDirty`) — expand destructuring to get `project`, `dispatch`, and use `useEditor` for `activeFloorId`.

```jsx
const handleDetectRooms = () => {
  const floor = project.floors.find(f => f.id === activeFloorId);
  if (!floor || floor.walls.length < 3) return;
  const detected = detectRooms(floor.walls);
  const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
  dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
};
```

Import `detectRooms` from `@/geometry/roomDetection` and `createRoom` from `@/domain/models`.

---

## Change 11: Rooms section in `Sidebar.jsx`

Add after the Windows section, following the same pattern:

```jsx
<div className={styles.section}>
  <div className={styles.sectionTitle}>
    Rooms <span className={styles.count}>{floor.rooms.length}</span>
  </div>
  {floor.rooms.map(r => (
    <div
      key={r.id}
      className={`${styles.item} ${selectedId === r.id ? styles.itemSelected : ''}`}
      onClick={() => selectObject(r.id, 'room')}
    >
      {r.name}
    </div>
  ))}
</div>
```

---

## Change 12: Room properties in `PropertiesPanel.jsx`

Add `RoomProperties` component:

```jsx
function RoomProperties({ room, dispatch, floorId }) {
  const areaM2 = room.area ? (room.area / 1_000_000).toFixed(2) : '—';
  const updateRoom = (updates) => {
    dispatch({ type: 'ROOM_UPDATE', floorId, room: { id: room.id, ...updates } });
